CWE-1240 ALERT. FORBIDDEN: Blowfish (BF_*, EVP_bf_*). Obsolete 64-bit block cipher, vulnerable to Sweet32 attack.
REPLACEMENT: AES-256-GCM via OpenSSL EVP interface. Provides authenticated encryption.
EXAMPLE (OpenSSL AES-256-GCM encrypt):
#include <openssl/evp.h>
#include <openssl/rand.h>
int encrypt_aes_gcm(const unsigned char *pt, int pt_len,
    const unsigned char *key, unsigned char *iv,
    unsigned char *ct, unsigned char *tag) {
    int len, ct_len;
    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
    if (!ctx) return -1;
    if (RAND_bytes(iv, 12) != 1) goto fail;
    if (EVP_EncryptInit_ex(ctx, EVP_aes_256_gcm(), NULL, key, iv) != 1) goto fail;
    if (EVP_EncryptUpdate(ctx, ct, &len, pt, pt_len) != 1) goto fail;
    ct_len = len;
    if (EVP_EncryptFinal_ex(ctx, ct + len, &len) != 1) goto fail;
    ct_len += len;
    if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GCM_GET_TAG, 16, tag) != 1) goto fail;
    EVP_CIPHER_CTX_free(ctx);
    return ct_len;
fail:
    EVP_CIPHER_CTX_free(ctx);
    return -1;
}
VERIFICATION: Final code MUST NOT reference BF_ or EVP_bf_ functions. Use EVP_aes_256_gcm() only.

